import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API = "http://localhost:3000/api";
const FASALLADA = ["Xadaano", "1aad", "2aad", "3aad", "4aad", "5aad", "6aad", "7aad", "8aad", "9aad", "10aad", "11aad", "12aad"];

// MAALMAHA ASBUUCA (Jimce waa laga booday)
const WEEK_DAYS = ["Sabti", "Axad", "Isniin", "Talaado", "Arbaco", "Khamiis"];

export default function App() {
  const [user, setUser] = useState(null);
  const [allStudents, setAllStudents] = useState([]);
  const [view, setView] = useState("classes");
  const [activeFasal, setActiveFasal] = useState("");
  const [adminTab, setAdminTab] = useState("attendance");
  const [studentTab, setStudentTab] = useState("exam");
  const [form, setForm] = useState({ id: "", pass: "" });
  const [showAttButtons, setShowAttButtons] = useState(false);

  useEffect(() => { if (user?.role === 'admin') load(); }, [user]);
  const load = () => axios.get(`${API}/data`).then(res => setAllStudents(res.data));

  const login = () => {
    axios.post(`${API}/login`, form).then(res => setUser(res.data)).catch(() => alert("ID ama Pass waa khaldan yahay!"));
  };

  const sync = (data) => { setAllStudents(data); axios.post(`${API}/update`, data); };

  // Shaqada lagu darayo ardayga
  const addStudent = (f) => {
    const n = prompt("Magaca Saddexan:");
    const meel = prompt("Ku dhashay:");
    const aaboTel = prompt("Tel Aabbaha:");
    const hooyoTel = prompt("Tel Hooyada:");
    const id = prompt("ID-ga:");
    if(n && id) {
      const s = { id, pass: "123", magaca: n, meel, aaboTel, hooyoTel, fasalka: f, exams: {}, att: {}, fee: "Ma bixin" };
      sync([...allStudents, s]);
    }
  };

  if (!user) return (
    <div style={st.loginBg}><div style={st.card}>
      <h1 style={{color:'#1a2a6c', margin:0}}>NAWAWI SCHOOL</h1>
      <p style={{color:'#7f8c8d', fontSize:'13px', marginBottom:'25px'}}>Official Management Portal</p>
      <input style={st.in} placeholder="Admin/Student ID" onChange={e => setForm({...form, id: e.target.value})} />
      <input style={st.in} type="password" placeholder="Password" onChange={e => setForm({...form, pass: e.target.value})} />
      <button style={st.btn} onClick={login}>SOO GAL</button>
    </div></div>
  );

  return (
    <div style={{display:'flex', height:'100vh', background:'#f0f2f5', fontFamily:'Segoe UI, sans-serif'}}>
      {/* SIDEBAR */}
      <div style={st.sidebar}>
        <div style={st.profile}>
          <div style={st.avatar}>🏫</div>
          <h3 style={{marginTop:'10px'}}>NAWAWI SCHOOL</h3>
          <p style={{fontSize:'12px', opacity:0.6}}>{user.magaca}</p>
        </div>
        <div style={st.nav}>
          {user.role === 'admin' ? (
            <>
              <button style={st.navBtn} onClick={() => { setView("classes"); setShowAttButtons(false); }}>🏠 Dashboard</button>
              <button style={st.navBtn} onClick={() => setAdminTab("attendance")}>📅 Xadiris (√/X)</button>
              <button style={st.navBtn} onClick={() => setAdminTab("exams")}>📝 Imtixaanada</button>
              <button style={st.navBtn} onClick={() => setAdminTab("fees")}>💰 Lacagaha</button>
            </>
          ) : (
            <>
              <button style={st.navBtn} onClick={() => setStudentTab("attendance")}>📅 My Attendance</button>
              <button style={st.navBtn} onClick={() => setStudentTab("exam")}>📝 My Result</button>
              <button style={st.navBtn} onClick={() => setStudentTab("fee")}>💰 My Fee</button>
            </>
          )}
        </div>
        <button style={st.out} onClick={() => setUser(null)}>Logout</button>
      </div>

      {/* CONTENT AREA */}
      <div style={{flex:1, padding:'40px', overflowY:'auto'}}>
        {user.role === 'admin' ? (
          view === "classes" ? (
            <div style={st.grid}>
              {FASALLADA.map(f => (
                <div key={f} style={st.classBox} onClick={() => { setActiveFasal(f); setView("list"); }}>
                  <h2 style={{margin:0, color:'#1a2a6c'}}>{f}</h2>
                  <p style={{fontSize:'13px', color:'#95a5a6'}}>{allStudents.filter(s => s.fasalka === f).length} Arday</p>
                  <button style={st.addBtn} onClick={(e) => { e.stopPropagation(); addStudent(f); }}>+ Add Student</button>
                </div>
              ))}
            </div>
          ) : (
            <div style={st.whiteCard}>
              <div style={{display:'flex', justifyContent:'space-between', alignItems:'center'}}>
                <button onClick={() => setView("classes")} style={st.backBtn}>← Back</button>
                {adminTab === "attendance" && (
                  <button 
                    onClick={() => setShowAttButtons(!showAttButtons)} 
                    style={{...st.toggleBtn, background: showAttButtons ? '#e74c3c' : '#27ae60'}}>
                    {showAttButtons ? "Close Attendance" : "Open Attendance Mode"}
                  </button>
                )}
              </div>
              <h2 style={{margin:'25px 0', borderLeft:'5px solid #1a2a6c', paddingLeft:'15px'}}>{activeFasal} - {adminTab.toUpperCase()}</h2>
              <table style={st.table}>
                <thead><tr style={st.thead}><th>ID</th><th>Magaca Ardayga</th><th>Maalinta</th><th>Action</th></tr></thead>
                <tbody>
                  {allStudents.filter(s => s.fasalka === activeFasal).map(s => (
                    <tr key={s.id} style={st.tr}>
                      <td><b>{s.id}</b></td>
                      <td style={{textAlign:'left'}}>{s.magaca}</td>
                      <td><span style={st.dayTag}>{WEEK_DAYS[new Date().getDay()] || "Khamiis"}</span></td>
                      <td>
                        {adminTab === "attendance" && showAttButtons && (
                          <div style={{display:'flex', gap:'8px', justifyContent:'center'}}>
                            <button style={st.pBtn} onClick={() => { s.att[WEEK_DAYS[new Date().getDay()]] = "√"; sync([...allStudents]); }}>√ Sax</button>
                            <button style={st.aBtn} onClick={() => { s.att[WEEK_DAYS[new Date().getDay()]] = "X"; sync([...allStudents]); }}>X Qalad</button>
                          </div>
                        )}
                        {adminTab === "attendance" && !showAttButtons && <span style={{color:'#bdc3c7'}}>🔒 Locked</span>}
                        {adminTab === "exams" && <input placeholder="Mark" style={st.miniIn} onBlur={(e) => { s.exams["Final"] = e.target.value; sync([...allStudents]); }} />}
                        {adminTab === "fees" && <select value={s.fee} onChange={(e) => { s.fee = e.target.value; sync([...allStudents]); }} style={st.select}><option>Ma bixin</option><option>Bixiyey</option></select>}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )
        ) : (
          /* STUDENT VIEW */
          <div style={st.stuCard}>
              <h1 style={{color:'#1a2a6c'}}>Nawawi Student Portal</h1>
              <div style={st.stuInfoRow}>
                  <span><b>Magaca:</b> {user.magaca}</span>
                  <span><b>Dhalasho:</b> {user.meel}</span>
                  <span><b>Aabo:</b> {user.aaboTel}</span>
              </div>
              <hr style={{opacity:0.1, margin:'25px 0'}}/>
              {studentTab === "attendance" && (
                  <div>
                      <h3>📅 Xadiriskaaga Asbuuca</h3>
                      <div style={st.attGrid}>
                          {WEEK_DAYS.map(day => (
                              <div key={day} style={{...st.dayBox, 
                                background: user.att[day] === "√" ? '#2ecc71' : user.att[day] === "X" ? '#e74c3c' : '#fff',
                                color: user.att[day] ? '#fff' : '#000'
                              }}>
                                <b>{day}</b><br/>
                                <span style={{fontSize:'20px'}}>{user.att[day] || "-"}</span>
                              </div>
                          ))}
                      </div>
                  </div>
              )}
              {studentTab === "exam" && <div style={st.box}><h3>📝 Natiijada Imtixaanka: <span style={{color:'#2980b9'}}>{user.exams["Final"] || 0}</span></h3></div>}
              {studentTab === "fee" && <div style={st.box}><h3>💰 Xaaladda Lacagta: <span style={{color: user.fee === 'Bixiyey' ? 'green' : 'red'}}>{user.fee}</span></h3></div>}
          </div>
        )}
      </div>
    </div>
  );
}

const st = {
  loginBg: { height:'100vh', display:'flex', justifyContent:'center', alignItems:'center', background:'linear-gradient(to right, #1a2a6c, #b21f1f, #fdbb2d)' },
  card: { background:'white', padding:'45px', borderRadius:'15px', textAlign:'center', width:'360px', boxShadow:'0 20px 40px rgba(0,0,0,0.3)' },
  in: { display:'block', width:'100%', padding:'14px', margin:'12px 0', borderRadius:'8px', border:'1px solid #ddd', fontSize:'15px' },
  btn: { width:'100%', padding:'14px', background:'#1a2a6c', color:'white', border:'none', borderRadius:'8px', cursor:'pointer', fontWeight:'bold', fontSize:'16px' },
  sidebar: { width:'250px', background:'#1c2833', color:'white', padding:'35px 20px', display:'flex', flexDirection:'column' },
  profile: { textAlign:'center', marginBottom:'40px', borderBottom:'1px solid #2c3e50', paddingBottom:'20px' },
  avatar: { fontSize:'50px' },
  nav: { flex:1 },
  navBtn: { display:'block', width:'100%', padding:'14px', background:'transparent', border:'none', color:'#bdc3c7', textAlign:'left', cursor:'pointer', borderRadius:'8px', marginBottom:'5px' },
  out: { padding:'12px', background:'#c0392b', color:'white', border:'none', borderRadius:'8px', fontWeight:'bold' },
  grid: { display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(200px, 1fr))', gap:'25px' },
  classBox: { background:'white', padding:'30px', borderRadius:'15px', textAlign:'center', cursor:'pointer', boxShadow:'0 4px 6px rgba(0,0,0,0.05)', borderBottom:'4px solid #1a2a6c' },
  addBtn: { background:'#f39c12', color:'white', border:'none', padding:'6px 12px', borderRadius:'6px', marginTop:'15px', fontSize:'11px', cursor:'pointer' },
  whiteCard: { background:'white', padding:'40px', borderRadius:'15px', boxShadow:'0 10px 25px rgba(0,0,0,0.05)' },
  backBtn: { background:'#f1f2f6', border:'none', padding:'8px 20px', borderRadius:'8px', cursor:'pointer', color:'#2f3542' },
  toggleBtn: { color:'white', border:'none', padding:'10px 20px', borderRadius:'8px', cursor:'pointer', fontWeight:'bold' },
  table: { width:'100%', borderCollapse:'collapse' },
  thead: { background:'#f8f9fa', color:'#2c3e50', height:'50px' },
  tr: { borderBottom:'1px solid #f1f2f6', textAlign:'center', height:'65px' },
  dayTag: { background:'#e8f0fe', color:'#1a73e8', padding:'4px 10px', borderRadius:'15px', fontSize:'12px', fontWeight:'bold' },
  pBtn: { background:'#2ecc71', color:'white', border:'none', padding:'8px 18px', borderRadius:'6px', cursor:'pointer' },
  aBtn: { background:'#e74c3c', color:'white', border:'none', padding:'8px 18px', borderRadius:'6px', cursor:'pointer' },
  miniIn: { width:'60px', padding:'8px', textAlign:'center', border:'1px solid #ddd', borderRadius:'4px' },
  select: { padding:'8px', borderRadius:'4px', border:'1px solid #ddd' },
  stuCard: { background:'white', padding:'50px', borderRadius:'20px', boxShadow:'0 10px 30px rgba(0,0,0,0.05)' },
  stuInfoRow: { display:'flex', gap:'30px', color:'#57606f' },
  attGrid: { display:'grid', gridTemplateColumns:'repeat(6, 1fr)', gap:'15px', marginTop:'25px' },
  dayBox: { padding:'20px 10px', textAlign:'center', borderRadius:'12px', border:'1px solid #eee', transition:'0.3s' }
};
